// Parse OpenSea asset_events into per-event normalized rows for courtyard_sales.
// Field mapping per CC-SESSION-BRIEF-COURTYARD-COLLECTOR-2026-05-27 + data-standard §10.2.

const CANONICAL_SETS = {
  'BASE': 'Base Set', 'BASE SET': 'Base Set', 'POKEMON BASE SET': 'Base Set',
  'FOSSIL': 'Fossil', 'POKEMON FOSSIL': 'Fossil',
  'JUNGLE': 'Jungle', 'POKEMON JUNGLE': 'Jungle',
  'TEAM ROCKET': 'Team Rocket', 'POKEMON TEAM ROCKET': 'Team Rocket',
  'GYM HEROES': 'Gym Heroes', 'POKEMON GYM HEROES': 'Gym Heroes',
  'GYM CHALLENGE': 'Gym Challenge', 'POKEMON GYM CHALLENGE': 'Gym Challenge',
  'WIZARDS BLACK STAR PROMOS': 'Wizards Black Star Promos', 'WBSP': 'Wizards Black Star Promos',
  'BEST OF GAME': 'Best of Game', 'BOG': 'Best of Game'
};

function findAttr(traits, names) {
  if (!Array.isArray(traits)) return null;
  for (const name of names) {
    const t = traits.find(x => (x.trait_type || '').toLowerCase() === name.toLowerCase());
    if (t && t.value != null && String(t.value).trim() !== '') return String(t.value).trim();
  }
  return null;
}

function normalizeGrader(raw) {
  if (!raw) return null;
  const u = raw.toUpperCase();
  if (u.includes('PSA')) return 'PSA';
  if (u.includes('CGC')) return 'CGC';
  if (u.includes('BGS') || u.includes('BECKETT')) return 'BGS';
  if (u.includes('SGC')) return 'SGC';
  return null;
}

function normalizeSet(raw) {
  if (!raw) return null;
  const u = raw.trim().toUpperCase();
  return CANONICAL_SETS[u] || null;
}

function normalizeEdition(raw) {
  if (!raw) return 'N/A';
  const u = raw.toUpperCase();
  if (u.includes('1ST') || u.includes('FIRST')) return '1st Edition';
  if (u.includes('SHADOW')) return 'Shadowless';
  if (u.includes('UNLIM')) return 'Unlimited';
  return 'N/A';
}

function normalizeCardNumber(raw) {
  if (!raw) return null;
  return String(raw).replace(/^#/, '').replace(/\/\d+$/, '').trim() || null;
}

const out = [];
const payload = $input.first().json || {};
const events = payload.asset_events || [];

for (const ev of events) {
  const nft = ev.nft || {};
  const traits = nft.traits || [];
  const payment = ev.payment || {};

  // grader is the strongest signal that this is a graded card we care about
  const grader = normalizeGrader(findAttr(traits, ['Grading Company', 'Grader', 'Grading', 'Authenticator']));
  if (!grader) continue;  // skip non-graded NFTs

  // USDC amount: quantity / 10^decimals
  let sold_price = null;
  if (payment.quantity != null && payment.decimals != null) {
    sold_price = Number(payment.quantity) / Math.pow(10, Number(payment.decimals));
  }

  out.push({
    json: {
      item_id: nft.identifier ? String(nft.identifier) : null,
      title: nft.name || null,
      card_name: findAttr(traits, ['Card Name', 'Name', 'Card']) || nft.name || null,
      grader,
      grade: findAttr(traits, ['Grade', 'Card Grade']),
      set_name: normalizeSet(findAttr(traits, ['Set Name', 'Set', 'Series'])),
      edition: normalizeEdition(findAttr(traits, ['Edition', 'Print Edition'])),
      print_variant: 'Standard',  // soft default; non-Standard variants rare on Courtyard
      card_number: normalizeCardNumber(findAttr(traits, ['Card Number', '#', 'Number'])),
      sold_price,
      transaction_hash: ev.transaction || null,
      seller_address: ev.seller || null,
      buyer_address: ev.buyer || null,
      seller_username: ev.seller || null,  // wallet addr; no on-chain username
      listing_url: nft.opensea_url || (nft.permalink || null),
      image_url: nft.image_url || nft.display_image_url || null,
      item_creation_date: ev.event_timestamp ? new Date(ev.event_timestamp * 1000).toISOString() : null,
      raw_payload: JSON.stringify(ev)
    }
  });
}

return out;
